import Foundation

func solve(nums: [Int64]) -> Int64 {
    let maxNum = 1000000
    var spf = [Int](repeating: 0, count: maxNum + 1)
    for i in 2...maxNum {
        if spf[i] == 0 {
            spf[i] = i
            for j in stride(from: i * 2, through: maxNum, by: i) {
                if spf[j] == 0 {
                    spf[j] = i
                }
            }
        }
    }

    var primeToIndices = [Int: [Int]]()
    for i in 0..<nums.count {
        let x = nums[i]
        if x == 1 {
            continue
        }
        var primes = Set<Int>()
        var num = Int(x)
        while num > 1 {
            let p = spf[num]
            primes.insert(p)
            while num % p == 0 {
                num /= p
            }
        }
        for p in primes {
            if var indices = primeToIndices[p] {
                indices.append(i)
                primeToIndices[p] = indices
            } else {
                primeToIndices[p] = [i]
            }
        }
    }

    let n = nums.count
    var distance = [Int64](repeating: -1, count: n)
    distance[0] = 0
    var queue = [Int64]()
    queue.append(0)

    while !queue.isEmpty {
        let i = queue.removeFirst()
        if i == Int64(n - 1) {
            return distance[i]
        }
        let iInt = Int(i)
        let next = iInt + 1
        if next < n {
            if distance[next] == -1 {
                distance[next] = distance[i] + 1
                queue.append(Int64(next))
            }
        }
        let prev = iInt - 1
        if prev >= 0 {
            if distance[prev] == -1 {
                distance[prev] = distance[i] + 1
                queue.append(Int64(prev))
            }
        }
        let x = nums[iInt]
        if x > 1 && spf[Int(x)] == Int(x) {
            if let indices = primeToIndices[Int(x)] {
                for j in indices {
                    if j != iInt {
                        if distance[Int64(j)] == -1 {
                            distance[Int64(j)] = distance[i] + 1
                            queue.append(Int64(j))
                        }
                    }
                }
            }
        }
    }
    return -1
}
